I'll help you swap 0.5 ETH to USDC on Arbitrum using the GMX SDK.

```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function swapEthToUsdc() {
  // ─── Setup ───────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl:
      "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ─── Resolve token addresses dynamically ─────────────────────────────────
  const { tokensData } = await sdk.markets.getMarketsInfo();

  // Find WETH — GMX uses WETH internally; native ETH is auto-wrapped
  const wethToken = Object.values(tokensData).find(
    (t) => t.symbol === "WETH"
  );
  const usdcToken = Object.values(tokensData).find(
    (t) => t.symbol === "USDC"
  );

  if (!wethToken || !usdcToken) {
    throw new Error("Could not find WETH or USDC in tokensData");
  }

  console.log("WETH address:", wethToken.address);
  console.log("USDC address:", usdcToken.address);

  // ─── Swap 0.5 ETH → USDC ─────────────────────────────────────────────────
  // 0.5 ETH = 500000000000000000n (18 decimals)
  const fromAmount = 500_000_000_000_000_000n; // 0.5 ETH

  console.log(`\nSwapping 0.5 ETH → USDC...`);

  const tx = await sdk.orders.swap({
    fromTokenAddress: wethToken.address, // WETH (GMX wraps native ETH)
    toTokenAddress: usdcToken.address,
    fromAmount,
    allowedSlippageBps: 100, // 1% slippage tolerance
    skipSimulation: true,
  });

  console.log("✅ Swap order submitted!");
  console.log("Transaction hash:", tx);
  console.log(
    "The GMX keeper will execute the swap within a few seconds at the oracle price."
  );
}

swapEthToUsdc().catch(console.error);
```

**What this does:**

| Parameter | Value |
|-----------|-------|
| From | 0.5 WETH (`500_000_000_000_000_000n`, 18 decimals) |
| To | USDC |
| Slippage | 1% (`allowedSlippageBps: 100`) |
| Chain | Arbitrum (chainId 42161) |
| Execution | GMX keeper executes within ~1–5 seconds at oracle price |

**Before running:**
1. Set `PRIVATE_KEY` env var — your wallet's private key (with `0x` prefix)
2. Ensure your wallet holds ≥ 0.5 ETH + a small amount of ETH for the execution fee (gas paid to the keeper)
3. Install deps: `npm install @gmx-io/sdk viem`

**Key notes:**
- GMX uses **WETH** internally — the SDK handles wrapping native ETH automatically when you pass the WETH address
- Token addresses are fetched dynamically (never hardcoded) since they can differ per deployment
- The swap is a **market order** — it executes at the current oracle price. Add `triggerPrice` to make it a limit order instead

