  // ─── Cancel all pending orders ────────────────────────────────────────────
  const orderKeys = pendingOrders.map((o) => o.key);

  console.log("Cancelling orders...");
  const result = await sdk.orders.cancelOrders(orderKeys);

  console.log("✅ Cancellation submitted!");
  console.log("Transaction hash:", result);

  return result;
}

cancelSwapOrder().catch(console.error);
