    : "0.000000";

  // Get current ETH price
  const ethPrice = wethToken?.prices?.minPrice
    ? Number(wethToken.prices.minPrice) / 1e30
    : null;

  console.log("=== ETH Balance ===");
  console.log(`Wallet:       ${account}`);
  console.log(`ETH (native): ${Number(ethBalance).toFixed(6)} ETH`);
  console.log(`WETH:         ${wethBalance} WETH`);
  if (ethPrice) {
    const ethUsdValue = Number(ethBalance) * ethPrice;
    console.log(`ETH Price:    $${ethPrice.toFixed(2)}`);
    console.log(`ETH Value:    $${ethUsdValue.toFixed(2)}`);
  }
}

checkEthBalance().catch(console.error);
