      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ── 2. Fetch token data ───────────────────────────────────────────────────

  const { tokensData } = await sdk.markets.getMarketsInfo();

  // Resolve WETH and USDT addresses dynamically
  const wethToken = Object.values(tokensData).find(
