  if (!usdtToken) throw new Error("USDT token not found in tokensData");

  console.log(`WETH address : ${wethToken.address}`);
  console.log(`USDT address : ${usdtToken.address}`);

  // ── 3. Execute swap ───────────────────────────────────────────────────────

  // 1 ETH = 1e18 (18 decimals)
