      const priceUsd = price ? Number(price) / 1e30 : null;

      return {
        symbol: indexToken?.symbol,
        market: m.marketTokenAddress,
        volumeUsd: Number(volumeUsd) / 1e30,
        priceUsd,
        longOI: Number(m.longInterestUsd) / 1e30,
        shortOI: Number(m.shortInterestUsd) / 1e30,
      };
    })
    .sort((a, b) => b.volumeUsd - a.volumeUsd)
    .slice(0, 10);

  return markets;
}
